# dual skeptic-H1 · S31-T3-A-E3
from collections import defaultdict, deque
adj = defaultdict(set)
for u, v in [('A','B'),('B','C'),('C','D')]:
    adj[u].add(v); adj[v].add(u)
q = deque([('A', ['A'])]); seen = {'A'}
path = None
while q:
    n, p = q.popleft()
    if n == 'D':
        path = p; break
    for m in sorted(adj[n]):
        if m not in seen:
            seen.add(m); q.append((m, p + [m]))
print("path", path)
print("len", len(path) if path else 0)
print("ok", path is not None)
# skeptic_check: form+pass contract

# dual skeptic-H1 · S31-T4-A-E1
from collections import defaultdict
edges=[('A','B'),('B','C'),('C','D')]
adj=defaultdict(set)
for u,v in edges:
    adj[u].add(v); adj[v].add(u)

def ego(seed, k):
    seen={seed}; layer={seed}
    for _ in range(k):
        nxt=set()
        for n in layer:
            for m in adj[n]:
                if m not in seen:
                    seen.add(m); nxt.add(m)
        layer = nxt
    return seen
print("k1", sorted(ego("A", 1)))
print("k2", sorted(ego("A", 2)))
print("ok", True)
# skeptic_check: form+pass contract
